        )
    elif cmd.key == "thicknessMm":
        els[cmd.element_id] = el.model_copy(
            update={"thickness_mm": float(_str_val(cmd.value))}
        )
    elif cmd.key == "name":
        els[cmd.element_id] = el.model_copy(update={"name": _str_val(cmd.value)})
